SELECT MIN(oMonetaryAmount.HASAMOUNT) AS AggResult1, oListedSecurity.HASLEGALNAME AS oListedSecurity_hasLegalName FROM FIBEN.LISTEDSECURITY AS oListedSecurity INNER JOIN FIBEN.MONETARYAMOUNT AS oMonetaryAmount ON oListedSecurity.HASLASTTRADEDVALUE = oMonetaryAmount.MONETARYAMOUNTID GROUP BY oListedSecurity.HASLEGALNAME ORDER BY AggResult1 ASC NULLS LAST